class Solution:
    def minimumOperations(self, nums, target):
        nums = nums[:]
        target = target[:]
        n = len(nums)
        count = 0
        while nums != target:
            i = 0
            while i < n and nums[i] == target[i]:
                i += 1
            if i == n:
                break
            sign = 1 if target[i] > nums[i] else -1
            j = i
            while j < n and nums[j] != target[j] and (target[j] - nums[j]) * sign > 0:
                j += 1
            for x in range(i, j):
                nums[x] += sign
            count += 1
        return count

