var minimumOperations = function(nums, target) {
    const n = nums.length;
    let posPrev = 0, negPrev = 0, total = 0;
    for (let i = 0; i < n; i++) {
        const d = target[i] - nums[i];
        const p = Math.max(d, 0);
        const ng = Math.max(-d, 0);
        total += Math.max(0, p - posPrev);
        total += Math.max(0, ng - negPrev);
        posPrev = p;
        negPrev = ng;
    }
    return total;
};
